/**
 * 台經．永續學院（VOS）首頁 — 高真度設計
 * 設計語彙參考 Brookings Institution / PIIE：襯線標題、細線分隔、
 * 留白節制、編輯感卡片列。品牌色取自 TIER 永續學院 Logo。
 */

const C = {
  navy: "#1E3A5C",
  navyDeep: "#132540",
  navyTint: "#E4EAF1",
  navyTintHover: "#D6DFEB",
  orange: "#D9622B",
  orangeSoft: "#F0A868",
  olive: "#7C9A3C",
  oliveTint: "#E9EFDD",
  oliveTintHover: "#DEE7CC",
  paper: "#FCFBF8",
  ink: "#1B2430",
  slate: "#6B7280",
  hairline: "#E4E1D7",
  card: "#FFFFFF",
};

const LOGO_SRC = "data:image/png;base64,";

const fontImport = `
@import url('https://fonts.googleapis.com/css2?family=Noto+Serif+TC:wght@500;600;700;900&family=Noto+Sans+TC:wght@400;500;600;700&family=Inter:wght@400;500;600;700&display=swap');
* { font-family: 'Noto Sans TC', 'Inter', sans-serif; }
.font-serif-tc { font-family: 'Noto Serif TC', serif; }
.font-num { font-family: 'Inter', 'Noto Sans TC', sans-serif; }
`;

function Eyebrow({ children, color = C.orange }) {
  return (
    <div
      className="flex items-center gap-2 mb-2 font-num"
      style={{ color }}
    >
      <span style={{ width: 16, height: 2, background: color }} />
      <span className="text-xs font-bold tracking-widest uppercase">{children}</span>
    </div>
  );
}

function Logo({ size = "normal" }) {
  const big = size === "large";
  return (
    <img
      src={LOGO_SRC}
      alt="台經．永續學院 TIER × Vision Of Sustainability"
      className={big ? "h-10" : "h-8"}
      style={{ width: "auto", objectFit: "contain" }}
    />
  );
}

function TagPill({ children }) {
  return (
    <span
      className="text-xs px-3 py-1 whitespace-nowrap border font-medium"
      style={{ borderColor: C.hairline, color: C.slate, background: "#fff" }}
    >
      {children}
    </span>
  );
}

function ArticleGraphic({ tone = "navy", pattern = "grid" }) {
  const base = tone === "navy" ? C.navy : tone === "orange" ? C.orange : C.olive;
  return (
    <svg viewBox="0 0 400 240" className="w-full h-full" preserveAspectRatio="xMidYMid slice">
      <rect width="400" height="240" fill={base} />
      {pattern === "grid" &&
        Array.from({ length: 6 }).map((_, i) => (
          <line key={i} x1={i * 70} y1="0" x2={i * 70} y2="240" stroke="#ffffff22" strokeWidth="1" />
        ))}
      <circle cx="320" cy="60" r="70" fill="#ffffff14" />
      <circle cx="60" cy="190" r="90" fill="#00000022" />
      <path d="M0 170 L100 120 L200 150 L300 90 L400 130 L400 240 L0 240 Z" fill="#ffffff12" />
    </svg>
  );
}

